// ============================================================
// Central Grants Description Backfill (queue-based)
// ------------------------------------------------------------
// Sweeps every row in central_grants whose description is NULL,
// empty, or shorter than THIN_LIMIT chars, then hands the whole
// batch off to the Enrich Throttle Queue (/webhook/enrich-queue).
// Enrich itself PATCHes central_grants as results come in, so this
// workflow no longer awaits responses or writes to Supabase.
//
// Benefits over the old implementation:
//   - No 10x parallel fan-out that crashed the task runner.
//   - No in-process loop holding the execution for 30+ minutes
//     (we now exit in seconds after queueing).
//   - Safe to re-run; enrich writes are idempotent.
//
// DRY_RUN=true: prints counts only, does not enqueue anything.
// ============================================================

const DRY_RUN          = true;   // <-- flip to false to actually enqueue
const THIN_LIMIT       = 200;    // matches enrich workflow's threshold
const PAGE_SIZE        = 1000;   // Supabase pagination page
const MAX_GRANTS       = null;   // optional safety cap (e.g. 200 for first real run)
const QUEUE_BATCH_SIZE = 500;    // rows per POST to the enrich queue

const SUPABASE_URL     = 'https://fgudhlcktsstwpxwtwzz.supabase.co/rest/v1';
const SUPABASE_KEY     = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZndWRobGNrdHNzdHdweHd0d3p6Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDk2NjA5NSwiZXhwIjoyMDg2NTQyMDk1fQ.lDXOCM7CStNfF0G-ZENg5x1dyQ0ytXHGtJ8DjQNd03I';
const ENRICH_QUEUE_URL = 'https://n8n.thebrownmine.com/webhook/enrich-queue';

const helpers = this.helpers;
const supaHeaders = {
  'apikey':        SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY,
  'Content-Type':  'application/json',
};

async function fetchAllCentralGrants() {
  const all = [];
  let offset = 0;
  const selectCols = 'id,title,funder_name,source,source_url,description,first_seen_at';
  while (true) {
    const rows = await helpers.httpRequest({
      method:  'GET',
      url:     SUPABASE_URL + '/central_grants?select=' + selectCols + '&order=first_seen_at.asc',
      headers: Object.assign({}, supaHeaders, {
        'Range-Unit': 'items',
        'Range':      offset + '-' + (offset + PAGE_SIZE - 1),
      }),
      json: true,
    });
    if (!Array.isArray(rows) || rows.length === 0) break;
    all.push.apply(all, rows);
    if (rows.length < PAGE_SIZE) break;
    offset += PAGE_SIZE;
  }
  return all;
}

// -------------------- main --------------------
const all = await fetchAllCentralGrants();
let thin = all.filter(function (g) { return (g.description || '').length < THIN_LIMIT; });
if (MAX_GRANTS && thin.length > MAX_GRANTS) thin = thin.slice(0, MAX_GRANTS);

const bySource = {};
for (let i = 0; i < thin.length; i++) {
  const key = thin[i].source || 'unknown';
  bySource[key] = (bySource[key] || 0) + 1;
}

let queued = 0;
const queueErrors = [];

if (!DRY_RUN && thin.length > 0) {
  for (let i = 0; i < thin.length; i += QUEUE_BATCH_SIZE) {
    const batch = thin.slice(i, i + QUEUE_BATCH_SIZE).map(function (g) {
      return {
        id:          g.id,
        title:       g.title || '',
        funder_name: g.funder_name || '',
        source_url:  g.source_url || '',
        description: g.description || '',
      };
    });
    try {
      await helpers.httpRequest({
        method:  'POST',
        url:     ENRICH_QUEUE_URL,
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({ grants: batch }),
        timeout: 30000,
      });
      queued += batch.length;
    } catch (e) {
      if (queueErrors.length < 20) {
        queueErrors.push({
          batchStart: i,
          size:       batch.length,
          message:    String(e.message || e).slice(0, 400),
        });
      }
    }
  }
}

return [{
  json: {
    dry_run:          DRY_RUN,
    total_scanned:    all.length,
    thin_found:       thin.length,
    queued:           queued,
    thin_limit:       THIN_LIMIT,
    max_grants_cap:   MAX_GRANTS,
    queue_batch_size: QUEUE_BATCH_SIZE,
    by_source:        bySource,
    errors: { queue: queueErrors },
  },
}];
